const raw = $('Claude Call 1').first().json.content[0].text;

// Strip markdown fences if present
const cleaned = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();

let parsed;
try {
  parsed = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Claude Call 1 JSON parse failed: ' + e.message + '\nRaw output: ' + raw);
}

return [{ json: parsed }];

const content = JSON.stringify($('Parse Claude Call 1 Response').first().json, null, 2);
const buffer = Buffer.from(content, 'utf8');
const base64 = buffer.toString('base64');

return [{ json: {}, binary: { data: { data: base64, mimeType: 'application/json', fileName: $('generate jobID').first().json.jobId + '-procedural.json' } } }];

